// MLB Underdog Filter Logic — 7-bucket structure
// Mirrors config.py exactly.

const TOSSUP_MIN = -130;
const TOSSUP_MAX = 130;
const EXTREME_FAVORITE_CUTOFF = -300;
const UNDERDOG_MIN = 131;  // Stays at 131 so watch_low games are still captured
const UNDERDOG_MAX = 260;

// New bucket structure — keep in sync with config.py
const BUCKETS = {
  watch_low:  [131, 135],  // track only, no wager alert
  slight:     [136, 150],
  prime:      [151, 160],
  moderate:   [161, 190],  // dead zone — low unit wager
  heavy:      [191, 220],
  very_heavy: [241, 249],
  watch_high: [250, 260],  // wager for now, watching
};

// These buckets are appended to the sheet but excluded from wager Telegram alerts
const TRACK_ONLY = new Set(['watch_low']);

function getBucket(odds) {
  for (const [label, [low, high]] of Object.entries(BUCKETS)) {
    if (odds >= low && odds <= high) return label;
  }
  return 'out_of_range';
}

const events = $input.first().json.body;
const today = new Date().toISOString().split('T')[0];

const stats = {
  total: events.length,
  no_odds: 0, no_sides: 0, tossup: 0, extreme: 0,
  out_of_range: 0, qualified: 0, watch_only: 0
};

const qualifying = [];

for (const event of events) {
  const home = event.home_team;
  const away = event.away_team;
  const teamOdds = {};
  teamOdds[home] = { prices: [], books: {} };
  teamOdds[away] = { prices: [], books: {} };

  for (const bookmaker of (event.bookmakers || [])) {
    for (const market of (bookmaker.markets || [])) {
      if (market.key !== 'h2h') continue;
      for (const outcome of market.outcomes) {
        if (teamOdds[outcome.name]) {
          teamOdds[outcome.name].prices.push(outcome.price);
          teamOdds[outcome.name].books[bookmaker.key] = outcome.price;
        }
      }
    }
  }

  if (!teamOdds[home].prices.length || !teamOdds[away].prices.length) {
    stats.no_odds++;
    continue;
  }

  const homeBest = Math.max(...teamOdds[home].prices);
  const awayBest = Math.max(...teamOdds[away].prices);

  let favorite, underdog;
  if (homeBest < awayBest) {
    favorite = home; underdog = away;
  } else if (awayBest < homeBest) {
    favorite = away; underdog = home;
  } else {
    stats.no_sides++;
    continue;
  }

  const favBest = Math.max(...teamOdds[favorite].prices);
  const dogBest = Math.max(...teamOdds[underdog].prices);

  // Toss-up check
  if (favBest >= TOSSUP_MIN && favBest <= TOSSUP_MAX &&
      dogBest >= TOSSUP_MIN && dogBest <= TOSSUP_MAX) {
    stats.tossup++;
    continue;
  }

  // Extreme favorite check
  if (favBest <= EXTREME_FAVORITE_CUTOFF) {
    stats.extreme++;
    continue;
  }

  // Qualifying range
  if (dogBest < UNDERDOG_MIN || dogBest > UNDERDOG_MAX) {
    stats.out_of_range++;
    continue;
  }

  const dogPrices = teamOdds[underdog].prices;
  const favPrices = teamOdds[favorite].prices;
  const dogAvg = Math.round(dogPrices.reduce((a, b) => a + b, 0) / dogPrices.length * 10) / 10;
  const favAvg = Math.round(favPrices.reduce((a, b) => a + b, 0) / favPrices.length * 10) / 10;

  const dogBooks = teamOdds[underdog].books;
  const bestBook = Object.entries(dogBooks)
    .reduce((best, [book, price]) => price > best[1] ? [book, price] : best, ['', -Infinity])[0];

  const bucket = getBucket(dogBest);
  const isTrackOnly = TRACK_ONLY.has(bucket);

  if (isTrackOnly) stats.watch_only++;
  else stats.qualified++;

  qualifying.push({
    json: {
      date: today,
      game_id: event.id,
      commence_time: event.commence_time || '',
      home_team: home,
      away_team: away,
      favorite: favorite,
      underdog: underdog,
      dog_odds_best: dogBest,
      dog_odds_avg: dogAvg,
      dog_best_book: bestBook,
      fav_odds_best: favBest,
      fav_odds_avg: favAvg,
      home_is_dog: underdog === home,
      bucket: bucket,
      num_books: (event.bookmakers || []).length,
      winner: '',
      dog_won: '',
      profit: '',
      _is_track_only: isTrackOnly,
    }
  });
}

if (qualifying.length === 0) {
  return [{ json: { _no_games: true, _stats: stats } }];
}

// Attach summary metadata to first item so message nodes can read it
qualifying[0].json._stats = stats;
qualifying[0].json._wager_count = qualifying.filter(q => !q.json._is_track_only).length;
qualifying[0].json._watch_count = qualifying.filter(q =>  q.json._is_track_only).length;

return qualifying;

// Build Telegram message — separates wager picks from watch-only games.
// watch_low (and any future TRACK_ONLY buckets) appear in a separate section,
// clearly marked as data-tracking only.

const items = $input.all();
const stats = items[0].json._stats || {};
const today = new Date().toISOString().split('T')[0];

const wagerItems = items.filter(i => !i.json._is_track_only && !i.json._no_games);
const watchItems  = items.filter(i =>  i.json._is_track_only);

let msg = `⚾ *MLB Underdog Report — ${today}*\n\n`;
msg += `📊 *Filter Results:*\n`;
msg += `Games today: ${stats.total || '?'}\n`;
msg += `Toss-ups: ${stats.tossup || 0} | Extreme: ${stats.extreme || 0} | Out of range: ${stats.out_of_range || 0}\n\n`;

if (wagerItems.length > 0) {
  msg += `✅ *${wagerItems.length} Qualifying Underdogs — WAGER:*\n\n`;
  for (const item of wagerItems) {
    const g = item.json;
    const homeAway = g.home_is_dog ? '(Home)' : '(Away)';
    msg += `🔹 *${g.underdog}* ${homeAway} +${g.dog_odds_best}\n`;
    msg += `   vs ${g.favorite} (${g.fav_odds_best})\n`;
    msg += `   Bucket: ${g.bucket} | Best: ${g.dog_best_book}\n\n`;
  }
} else {
  msg += `No wager-eligible underdogs today.\n\n`;
}

if (watchItems.length > 0) {
  msg += `👁 *${watchItems.length} Watch-Only — track, do not wager:*\n`;
  for (const item of watchItems) {
    const g = item.json;
    msg += `   ${g.underdog} +${g.dog_odds_best} vs ${g.favorite} | ${g.bucket}\n`;
  }
}

return [{ json: { message: msg } }];

// No qualifying games at all today (not even watch-only)
const stats = $input.first().json._stats || {};
const today = new Date().toISOString().split('T')[0];

let msg = `⚾ *MLB Underdog Report — ${today}*\n\n`;
msg += `No qualifying underdogs today.\n\n`;
msg += `📊 ${stats.total || '?'} games checked:\n`;
msg += `Toss-ups: ${stats.tossup || 0} | Extreme: ${stats.extreme || 0} | Out of range: ${stats.out_of_range || 0}`;

return [{ json: { message: msg } }];
